-- ============================================
-- CAS ASSURANCE — Cabinet courtage Suisse romande
-- Version SQLite — 6 tables, ~100 lignes
-- ============================================
CREATE TABLE courtier (id_courtier INTEGER PRIMARY KEY AUTOINCREMENT, nom TEXT NOT NULL, prenom TEXT NOT NULL, email TEXT NOT NULL UNIQUE, telephone TEXT, date_embauche TEXT NOT NULL, taux_commission REAL NOT NULL DEFAULT 5.00);
CREATE TABLE type_assurance (id_type INTEGER PRIMARY KEY AUTOINCREMENT, libelle TEXT NOT NULL, domaine TEXT NOT NULL, prime_min_annuelle REAL NOT NULL, prime_max_annuelle REAL, description TEXT);
CREATE TABLE client (id_client INTEGER PRIMARY KEY AUTOINCREMENT, nom TEXT NOT NULL, prenom TEXT NOT NULL, date_naissance TEXT NOT NULL, email TEXT UNIQUE, telephone TEXT, adresse TEXT, ville TEXT NOT NULL, code_postal TEXT NOT NULL, type_client TEXT NOT NULL DEFAULT 'Particulier');
CREATE TABLE police (id_police INTEGER PRIMARY KEY AUTOINCREMENT, id_client INTEGER NOT NULL REFERENCES client(id_client), id_type INTEGER NOT NULL REFERENCES type_assurance(id_type), id_courtier INTEGER NOT NULL REFERENCES courtier(id_courtier), numero_police TEXT NOT NULL UNIQUE, date_debut TEXT NOT NULL, date_fin TEXT NOT NULL, prime_annuelle REAL NOT NULL, franchise REAL NOT NULL DEFAULT 500.00, statut TEXT NOT NULL DEFAULT 'Active');
CREATE TABLE sinistre (id_sinistre INTEGER PRIMARY KEY AUTOINCREMENT, id_police INTEGER NOT NULL REFERENCES police(id_police), date_sinistre TEXT NOT NULL, description TEXT NOT NULL, montant_declare REAL NOT NULL, montant_rembourse REAL DEFAULT 0, statut TEXT NOT NULL DEFAULT 'Declare', date_resolution TEXT);
CREATE TABLE paiement_prime (id_paiement INTEGER PRIMARY KEY AUTOINCREMENT, id_police INTEGER NOT NULL REFERENCES police(id_police), montant REAL NOT NULL, date_paiement TEXT NOT NULL, date_echeance TEXT NOT NULL, mode_paiement TEXT NOT NULL, statut TEXT NOT NULL DEFAULT 'Paye');

